pub fn get_species_by_name(name: &str) -> Option<&'static SpeciesData> {
    SPECIES_DATA.iter().find(|s| s.name.eq_ignore_ascii_case(name))
}

pub fn get_species_by_id(id: u16) -> Option<&'static SpeciesData> {
    SPECIES_DATA.iter().find(|s| s.id == id)
}
